module multi_pipe_4bit(
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);
parameter size = 4;
reg [3:0] a_extend, b_extend;
reg [7:0] partial_products [0:size-1];
reg [7:0] sum [0:size-1];
integer i;
// Extend input signals
always @(*) begin
    a_extend = {{size{1'b0}}, mul_a};
    b_extend = {{size{1'b0}}, mul_b};
end
// Generate partial products
generate
    genvar i;
    for (i = 0; i < size; i = i + 1) begin : gen_partial_products
        always @(*) begin
            if (b_extend[i] == 1'b1) begin
                partial_products[i] = a_extend << i;
            end else begin
                partial_products[i] = 'd0;
            end
        end
    end
endgenerate
// Add partial products
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        for (i = 0; i < size; i = i + 1) begin
            sum[i] <= 'd0;
        end
    end else begin
        sum[0] <= partial_products[0];
        for (i = 1; i < size; i = i + 1) begin
            sum[i] <= sum[i-1] + partial_products[i];
        end
    end
end
// Calculate final product
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_out <= 'd0;
    end else begin
        mul_out <= sum[size-1];
    end
end
endmodule
